Insert into TSK_TASKS (TASK_ID,TASK_KEY,TEAM_ID,TITLE,DESCRIPTION,TYPE_ID,STATUS_ID,COMPLEXITY_ID,APPLICATION_ID,OWNER_MEMBER_ID,CREATED_BY_MEMBER_ID,PRIORITY_CODE,START_DATE,DUE_DATE,COMPLETED_DATE,ESTIMATED_HOURS,ACTUAL_HOURS,PERCENT_COMPLETE,EXTERNAL_REFERENCE,CREATED_AT,CREATED_BY,UPDATED_AT,UPDATED_BY,TOPIC_GROUP_ID) values (2828,'TASK-002828',1,'Investigate the best way to show the schedule of events (list and calendar)','<p>Need a way to schedule a session for a day, timeslot, room and session type.&nbsp;</p><p>For example, if the event admin wants to schedule all the HOLs, they would see all the days and timeslots that are 90-120 min and then click on it and select the session for that timeslot. In addition, it should make sure that the speaker for that session is not already allocated to do something else at the same time.</p><p>&nbsp;</p>',2,5,null,7,3,1,'HIGH',null,null,to_date('04-MAR-26','DD-MON-RR'),null,null,100,'APPDEV_XLSX_ID:2524',to_timestamp('16-DEC-25 12.00.00.000000000 AM','DD-MON-RR HH.MI.SSXFF AM'),'MARCIE.YOUNG@ORACLE.COM',to_timestamp('28-MAY-26 11.25.11.708507000 PM','DD-MON-RR HH.MI.SSXFF AM'),'WKSP_DBAPPDEV',null);
Insert into TSK_TASKS (TASK_ID,TASK_KEY,TEAM_ID,TITLE,DESCRIPTION,TYPE_ID,STATUS_ID,COMPLEXITY_ID,APPLICATION_ID,OWNER_MEMBER_ID,CREATED_BY_MEMBER_ID,PRIORITY_CODE,START_DATE,DUE_DATE,COMPLETED_DATE,ESTIMATED_HOURS,ACTUAL_HOURS,PERCENT_COMPLETE,EXTERNAL_REFERENCE,CREATED_AT,CREATED_BY,UPDATED_AT,UPDATED_BY,TOPIC_GROUP_ID) values (2829,'TASK-002829',1,'Test out the Rainfocus API with Oracle AI Lakehouse Summit - Singapore',TO_CLOB(q'[<p>Test out the post session Rainfocus API for Oracle AI Lakehouse Summit - Singapore event</p><p>Event Code: oaiwsingapore26</p><p>We need to create this event in DEV so you can test it out</p><p>Here is the Rainfocus Swagger documentation for you to be&nbsp;able to pull data regarding AI World 2025:</p><p><a href="https://events.rf.oracle.com/apidocs/index.jsp?apiProfileId=1762534065150002YmoF&amp;version=2">https://events.rf.oracle.com/apidocs/index.jsp?apiProfileId=1762534065150002YmoF&amp;v]')
