Insert into TSK_TASKS (TASK_ID,TASK_KEY,TEAM_ID,TITLE,DESCRIPTION,TYPE_ID,STATUS_ID,COMPLEXITY_ID,APPLICATION_ID,OWNER_MEMBER_ID,CREATED_BY_MEMBER_ID,PRIORITY_CODE,START_DATE,DUE_DATE,COMPLETED_DATE,ESTIMATED_HOURS,ACTUAL_HOURS,PERCENT_COMPLETE,EXTERNAL_REFERENCE,CREATED_AT,CREATED_BY,UPDATED_AT,UPDATED_BY,TOPIC_GROUP_ID) values (3019,'TASK-003019',1,'Create Conference Planner Documentation',TO_CLOB(q'[<ul><li>Create a Conference</li><li>CFP<ul><li>Add an Abstract and add to a conference</li><li>Accept Session&nbsp;</li><li>Create Travel Request</li></ul></li><li>Oracle Managed Account<ul><li>Setup Tracks and Session Type Quotas</li><li>Submit Proposed Session</li><li>Reallocate Sessions into tracks and accept sessions</li><li>Assign Speakers</li><li>Sync with Rainfocus<ul><li>Generate Rainfocus IDs</li><li>Send to Sessions to Rainfocus and get Rainfocus IDs</li></ul></li><li>Manage Session Co]')
Insert into TSK_TASKS (TASK_ID,TASK_KEY,TEAM_ID,TITLE,DESCRIPTION,TYPE_ID,STATUS_ID,COMPLEXITY_ID,APPLICATION_ID,OWNER_MEMBER_ID,CREATED_BY_MEMBER_ID,PRIORITY_CODE,START_DATE,DUE_DATE,COMPLETED_DATE,ESTIMATED_HOURS,ACTUAL_HOURS,PERCENT_COMPLETE,EXTERNAL_REFERENCE,CREATED_AT,CREATED_BY,UPDATED_AT,UPDATED_BY,TOPIC_GROUP_ID) values (3020,'TASK-003020',1,'ACE: Poll issue (Error after submit of incomplete Poll)',TO_CLOB(q'[<p>Fix Poll issue:</p><p>&nbsp;</p><p style="margin-left:0;">he issue with this poll was as follows:<br><br>&nbsp;</p><ol><li>The error only happens when people do not answer all the required questions.<ol><li>In which case the response is still recorded but as an error.</li></ol></li><li>Usually this is not a problem as people should be able to resubmit. But this Poll was set with "Can Update Answers" to No. Which means resubmit is not allowed.</li><li>If Can Update Answers was Yes, upon saving]')
