Insert into TSK_TASKS (TASK_ID,TASK_KEY,TEAM_ID,TITLE,DESCRIPTION,TYPE_ID,STATUS_ID,COMPLEXITY_ID,APPLICATION_ID,OWNER_MEMBER_ID,CREATED_BY_MEMBER_ID,PRIORITY_CODE,START_DATE,DUE_DATE,COMPLETED_DATE,ESTIMATED_HOURS,ACTUAL_HOURS,PERCENT_COMPLETE,EXTERNAL_REFERENCE,CREATED_AT,CREATED_BY,UPDATED_AT,UPDATED_BY,TOPIC_GROUP_ID) values (3036,'TASK-003036',1,'Add yourself as a speaker for the fake session and sync with rainfocus',TO_CLOB(q'[<p>This is going to be a little tricky because I think your going to need to use the <a href="https://events.rf.oracle.com/apidocs/index.jsp?apiProfileId=1762534065150002YmoF&amp;version=2#/Sessions/get_sessionRoles"><strong>/sessionRoles</strong></a><strong> </strong>API to see what you get and then see what participants are there for the fake session. And then you will add yourself as another participant.</p><p>Before you run it, let's take a look at it and then send it to Jon to make sure it ]')
